5b4w4L8n74gg.VEu8DmcQMTCdERDV7jHbEtXhzGpD-eOZl66dwOGpdxEg.JPEG/CC5C6632-9A49-410F-8EA7-DFF12723B85D.jpeg?type=w1500_60_sharpen"],"gallery":["https://ldb-phinf.pstatic.net/20220412_56/1649753852872KF5Xa_JPEG/KakaoTalk_20220412_162438891_10.jpg","https://ldb-phinf.pstatic.net/20220412_160/1649753853164pl70K_JPEG/KakaoTalk_20220412_162438891_16.jpg","https://ldb-phinf.pstatic.net/20220412_188/1649753852509tRcBS_JPEG/KakaoTalk_20220412_162438891_25.jpg"],"representative":"https://ldb-phinf.pstatic.net/20220412_56/1649753852872KF5Xa_JPEG/KakaoTalk_20220412_162438891_10.jpg"},"reviews":[{"body":"오늘 12살 아들 헤어컷하고 왔는데 아이 스타일도 꼼꼼하게 봐주시고 원하는 느낌을 잘 반영해주셨어요. 몇 번 방문하면서 디자이너 선생님이랑 친해졌는데 항상 친절하게 대해주셔서 아이도 편하게 머리 자르는 것 같아요 😊 낯가리는 아이들도 부담 없이 방문하기 좋을 것 같고, 전체적으로 만족해서 다음에도 계속 방문할 예정입니다!","images":["https://pup-review-phinf.pstatic.net/MjAyNjA1MjFfMjc5/MDAxNzc5MzYwODY5MTU2.iGtfaqerfoNxFFR7PKFgVl7pXrSLxJG0SbdjJPvsakkg.cLSSDKs_VLJaQT12vKhej8uMqs7hS-bHb2-mCKkjOhkg.JPEG/1000021811.jpg.jpg?type=w1500_60_sharpen","https://pup-review-phinf.pstatic.net/MjAyNjA1MjFfMjA0/MDAxNzc5MzYwODY5MTA2.3T4ASWPE_BRGlpyY73DaNfMLOpbz_mIhlXg0vqp3_hIg.409HTMBIvBXijhL8NAsdsNV5NEiT95b9ZT41DYHTHQEg.JPEG/1000021809.jpg.jpg?type=w1500_60_sharpen"],"visited":"5.21.목","keywords":["원하는 스타일로 잘해줘요","친절해요","매장이 청결해요"],"ownerReply":"안녕하세요 진영 고객님 :) \n담당해드린 디자이너 채시아 입니다 💜\n믿고 방문해주시고 만족해주셔서 감사합니다 🎀\n덕분에 항상 즐겁고 감사하게 일하고 있어요 💛\n앞으로도 이쁘고 멋지게 해드릴게요✨\n\n ❣️ 항상 감사합니다 ❣️"},{"body":"채시아 디자이너 선생님의\n전문가입장의\n꼼꼼한 디렉션으로 조율해서 \n원하는 헤어스타일이 나왔습니다!\n생각보다 멋진스타일로 완성되서\n만족스럽네요!!\n\n시아 샘..\n커트를 아주 잘하시네요!","images":["https://pup-review-phinf.pstatic.net/MjAyNjA2MDJfMTY4/MDAxNzgwMzg4NTQ4NjA2.m7UPiEX8apBAHtbxdvqX4irTxjgQndf2BH-G2aX8Je4g.hOQIvBhfTFvzimrxl9XCJeGO2DzNkrVSiAKjYLs_QEEg.JPEG/6DF4DC63-9A10-4074-BC05-F8B2DC62DC6C.jpeg?type=w1500_60_sharpen","https://pup-review-phinf.pstatic.net/MjAyNjA2MDJfMTk4/MDAxNzgwMzg4NTQ4MTc1.CgvKl4chnekJsS7WWImVvqlODt16kZEJYvFs_hvJudsg.yq-Q31UIFoB8rw5gRIYh6upK_kYqYVS_bV40hmcQbCMg.JPEG/5C6E0F2A-ABC4-4CCD-B9D3-F8930419258A.jpeg"],"visited":"6.2.화","keywords":["원하는 스타일로 잘해줘요","스타일 추천을 잘해줘요","고급스러워요","맞춤 케어를 잘해줘요","시술이 꼼꼼해요"],"ownerReply":null},{"body":"왕십리역 샴푸맛집 미용실 헤어더뷰 퍼스트왕십리역점에 건재쌤한테 다운펌하러 다녀왔습니다.\n\n항상 다른직원분들도 친절하시고, 건재쌤은 머리 진짜 꼼꼼하게 봐주시는 거 같아요.\n\n다운펌 너무 맘에 들고, 이쁜 머리하러 다음에 또 가겠습니다!!","images":["https://pup-review-phinf.pstatic.net/MjAyNjA1MzFfMTI1/MDAxNzgwMjM0NTUxMTEz.GW60T55FsFTdQQAl7d8Qrh1iDi2mAihdZzTybic-zaEg.79pKcPOX3VRjmgKckn2i8cenS85jAfJeGRnreLBbp2gg.JPEG/11264F10-243E-44DF-9A0A-84E68D347AEE.jpeg?type=w1500_60_sharpen"],"visited":"5.22.금","keywords":["원하는 스타일로 잘해줘요","손상이 적어요","남자 머리를 잘해요","친절해요","시술이 꼼꼼해요"],"ownerReply":"안녕하세요 고객님 \"디자이너 건재\" 입니다 :)\n이번에도 깔끔하게 \"다운펌\" 으로 \"시스루댄디컷\" 도와드렸는데 항상 멀리서 믿고 방문해주셔서 정말로 너무 감사합니다!!\n언제든지 스타일 변화가 필요하시거나 중요한 일정이 생기시면 맞춰서 도와드릴게요!!\n소중한 리뷰 너무나도 감사드리고 이번 한 주도 화이팅 하세요!!\n다음에 또 뵐게요!! :)"},{"body":"오늘 회사 중간에 농띵이 ~~ 비도 오고 꿀꿀할땐 클리닉 아닌가요?! ㅋㅋㅋㅋ 제가 받은 시술은 채시아 디자이너쌤한테 집중케어 받았어요!! 4단계로 과정이 많다보니 꼼꼼하게 케어받는 기분이었어요! 푸석 푸석에서 완전 매끈 매끈으로 거듭났어요!! 그리고 역이랑 바로 이어져 있어서 더 좋았어요 종종 머리하러 올 거 같아요!!","images":["https://pup-review-phinf.pstatic.net/MjAyNjA1MjZfMTE2/MDAxNzc5Nzg0MjIzMzM2.YvOGUXIMthEoXXTF4EF1aIDvQVAeS0Il5b4w4L8n74gg.VEu8DmcQMTCdERDV7jHbEtXhzGpD-eOZl66dwOGpdxEg.JPEG/CC5C6632-9A49-410F-8EA7-DFF12723B85D.jpeg?type=w1500_60_sharpen","https://pup-review-phinf.pstatic.net/MjAyNjA1MjZfMjgw/MDAxNzc5Nzg0MjIyNTE0.RZVC4XxDJIpAdbduBOt6qqqKxwq08UKkI5knjORHg6Eg.1eOE9Nmg-jd2-qyvh25lkl1KVgtPWOLY8kgNtN8XoSog.JPEG/22F9A491-6343-449F-AE55-8D7F15673D93.jpeg"],"visited":"5.26.화","keywords":["손상이 적어요","자연스러워요","맞춤 케어를 잘해줘요","클리닉 효과가 좋아요"],"ownerReply":"안녕하세요 희경 고객님 :) \n담당해드린 디자이너 채시아 입니다 💜\n믿고 방문해주시고 만족해주셔서 감사합니다 🎀\n덕분에 항상 즐겁고 감사하게 일하고 있어요 💛\n앞으로도 이쁘고 멋지게 해드릴게요✨\n\n ❣️ 항상 감사합니다 ❣️"},{"body":"저번 머리를 하고 뿌리가 너무 많이 자라서 급하게 예약하느라 무슨머리를 할지 고르지 못하고 갔는데도 하정쌤께서 같이 저한테 어울릴만한 머리도 추천해주시구..더 저랑 잘 맞는 머리색으로 만들어 주셨숩니다..ㅠㅠ🥹❤️\n이번머리 진짜 역대급..!주변에서도 더더 예쁘다고 무슨색이냐 물어보네용..제 첫 탈색 그리고 염색 전부 하정쌤께서 예쁘게 해주신 덕분에 예쁜머리로 예쁜 사진찍고 넘 좋았습니다..외모정병 완치..🥺💗💗 부끄럽게 많이 자란 제 뿌리를 이런머리로 다시 태어나게 해주셔서 감사합니다….💗쌤 최고..✨","images":["https://pup-review-phinf.pstatic.net/MjAyNjA2MDRfMjM1/MDAxNzgwNTU2NzUwMjAy.uJ6w0bl1Yq0karAvVTj4r7IZSVR_Km2Ll0HOjBpRs9Ug.cgZa2zpewvHxe-5NqfaguSPpln7UwIUtj2JzAuKad-gg.JPEG/D298279A-151A-40A4-9EEE-565F05D8D4AE.jpeg?type=w1500_60_sharpen","https://pup-review-phinf.pstatic.net/MjAyNjA2MDRfMyAg/MDAxNzgwNTU2NzUwNDY4.N-qE1Qcw6fbbanlAVij1y5xlTnH6PixRCfM7swrSSKUg.XJH34KvLkwSdH5BS8JS7j8K40C88jpyvF6L0cNXxfksg.JPEG/A0701784-6BEE-4F5A-9214-95FC0F7817C6.jpeg?type=w1500_60_sharpen","https://pup-review-phinf.pstatic.net/MjAyNjA2MDRfMjI5/MDAxNzgwNTU2NzUwMDAw.9co1ikrUunrm4kBm82lWuVu9CKZ20-PHQumBraHLqRgg.qicV7qNz1rBNCWYWGl2OPtIamTQH3q9pN7Ef1rQqWd4g.JPEG/96384F3E-F45B-4592-A0E1-6D511E792051.jpeg?type=w1500_60_sharpen"],"visited":"6.2.화","keywords":["원하는 스타일로 잘해줘요","맞춤 케어를 잘해줘요","스타일 추천을 잘해줘요","친절해요","시술이 꼼꼼해요"],"ownerReply":null}],"category":"헤어","hasEvent":false,"minPrice":25200,"hoursText":"금 11:00~21:00 / 토 10:00~20:00 / 일 10:00~20:00 / 월 11:00~21:00 / 화 11:00~21:00 / 수 11:00~21:00 / 목 11:00~21:00","instagram":null,"priceTier":"2만원대","categories":["헤어"],"reservable":true,"reviewCount":26382,"reviewTotal":26382,"roadAddress":"서울 성동구 왕십리광장로 17 지하2층 A01호, A02호","conveniences":["예약","무선 인터넷","대기공간","반려동물 동반","주차"],"firstVisitDeal":false,"blogReviewTotal":804,"reservationRoutes":[{"type":"naver","label":"네이버로 예약","value":"https://m.booking.naver.com/booking/13/bizes/665632/items/5729535"},{"type":"talktalk","label":"톡톡으로 문의","value":"http://talk.naver.com/w48z7t?frm=mnmb"},{"type":"phone","label":"전화로 예약","value":"02-2200-6100"}],"representativeImage":"https://ldb-phinf.pstatic.net/20220412_56/1649753852872KF5Xa_JPEG/KakaoTalk_20220412_162438891_10.jpg"}','[{"name":"예약","times":["10:00","10:30","11:00","11:30","12:00","12:30","13:00","13:30","14:00","14:30","15:00","15:30"]}]','N페이 매장결제시 신규고객 펌/염색/컷 20%할인, 기존 10%할인','20% 할인',false,true,false,false,true) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name,today_open=EXCLUDED.today_open,slot_summary=EXCLUDED.slot_summary,min_price